import java.util.Scanner;

public class SafeBufferCopyExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string:");
        String userInput = scanner.nextLine();

        char[] buffer = new char[10];

        // Safely copy user input into the buffer without causing buffer overflow
        int lengthToCopy = Math.min(userInput.length(), buffer.length);
        userInput.getChars(0, lengthToCopy, buffer, 0);

        System.out.println("Buffer contents: ");
        for (char c : buffer) {
            System.out.print(c);
        }

    }
}

